      "security_level": "High",
      "dre_model": "DRE-X2",
      "is_certified": false
    }
  },
  "list_ballot_batches": {
    "description": "Returns a list of all ballot batches associated with the precinct, including their current status and tally variances.",
    "parameters": {
      "type": "object",
      "properties": {
        "precinct_id": {
          "type": "string",
          "description": "The unique identifier for the precinct."
