      "type": "object",
      "properties": {
        "precinct_id": {
          "type": "string",
          "description": "The unique identifier for the precinct."
        },
        "step_number": {
          "type": "integer",
          "description": "The sequence number of the protocol step (e.g., 1, 2, 3)."
        },
        "protocol_code": {
          "type": "string",
          "description": "The security code or operation name required for this step."
        }
      },
      "required": [
        "precinct_id",
        "step_number",
        "protocol_code"
      ]
    },
    "example_output": {
      "step_status": "Authorized",
      "next_required_step": 2
    }
  },
