    "description": "Retrieves detailed diagnostic information for a specific flagged ballot batch to determine the source of the variance.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The unique identifier for the ballot batch."
        }
      },
      "required": [
        "batch_id"
      ]
    },
    "example_output": {
      "variance_reason": "Double-fed scan in unit #4",
      "suggested_adjustment": -1
    }
  },
  "update_batch_resolution": {
    "description": "Updates a ballot batch status and records the resolution details. This tool adjusts the tally to match verified physical counts.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The unique identifier for the ballot batch."
        },
        "new_status": {
          "type": "string",
          "enum": [
            "Resolved",
            "Unresolved"
          ],
          "description": "The target status for the batch."
        },
        "resolution_notes": {
          "type": "string",
          "description": "Explanation of the correction made."
        },
        "adjustment_value": {
          "type": "number",
          "description": "The numerical adjustment applied to resolve the variance."
        }
      },
      "required": [
        "batch_id",
        "new_status",
        "resolution_notes",
        "adjustment_value"
      ]
    },
    "example_output": {
      "batch_id": "B-001",
      "new_status": "Resolved",
      "updated_at": "2023-10-27T10:00:00Z"
    }
  },
  "get_reconciliation_summary": {
    "description": "Retrieves the aggregated reconciliation stats to verify if all discrepancies have been cleared.",
    "parameters": {
      "type": "object",
      "properties": {
        "precinct_id": {
          "type": "string",
          "description": "The unique identifier for the precinct."
        }
      },
      "required": [
        "precinct_id"
      ]
    },
    "example_output": {
      "total_batches": 10,
      "resolved_batches": 10,
      "flagged_batches": 0,
      "total_variance": 0
    }
  },
  "certify_precinct": {
    "description": "Finalizes the audit and moves the precinct into a certified state. Only allowed if all discrepancies are resolved.",
    "parameters": {
      "type": "object",
      "properties": {
        "precinct_id": {
          "type": "string",
          "description": "The unique identifier for the precinct."
        }
      },
      "required": [
        "precinct_id"
      ]
    },
